import React, { useState } from "react";
import "../styles/GeneralChat.css";

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hello 🌱"
    }
  ]);

  const [input, setInput] = useState("");
  const [hasGreeted, setHasGreeted] = useState(false);

  const therapistReply = (userText) => {
    const text = userText.toLowerCase().trim();

    /* ================= GREETING (ONLY ONCE) ================= */
    if (
      !hasGreeted &&
      ["hi", "hello", "hey", "hai"].includes(text)
    ) {
      setHasGreeted(true);
      return "Hello 🌼 I’m here with you. Take your time.";
    }

    /* ================= HAPPY MOOD ================= */
    if (
      text.includes("happy") ||
      text.includes("good") ||
      text.includes("great") ||
      text.includes("excited") ||
      text.includes("joy") ||
      text.includes("positive")
    ) {
      return (
        "That’s really nice to hear 😊\n\n" +
        "What’s been making you feel happy today?"
      );
    }

    if (
      text.includes("friends") ||
      text.includes("family") ||
      text.includes("success") ||
      text.includes("achievement") ||
      text.includes("vacation") ||
      text.includes("trip")
    ) {
      return (
        "That sounds wonderful 🌸\n\n" +
        "How does this happiness show up for you — more energy, calmness, or motivation?"
      );
    }

    if (
      text.includes("calm") ||
      text.includes("peace") ||
      text.includes("relaxed")
    ) {
      return (
        "Feeling calm and peaceful is really valuable 🤍\n\n" +
        "What helps you stay in this positive state?"
      );
    }

    /* ================= SONG REQUEST ================= */
    if (
      text.includes("song") ||
      text.includes("music") ||
      text.includes("suggest")
    ) {
      return (
        "Sure 🎶 Here are some songs based on positive & calming moods:\n\n" +
        happySongs +
        "\nMusic can gently lift your mood. Tell me how you feel after listening 😊"
      );
    }

    /* ================= STRESS (UNCHANGED) ================= */
    if (
      text.includes("stress") ||
      text.includes("stressed") ||
      text.includes("overwhelmed")
    ) {
      return (
        "I’m really sorry you’re feeling this way 🤍\n\n" +
        "Stress can come from many areas of life — studies, work, family, money, health, relationships, or future worries.\n\n" +
        "What do you feel is causing this stress for you?"
      );
    }

    if (
      text.includes("study") ||
      text.includes("exam") ||
      text.includes("college")
    ) {
      return "Academic pressure can be overwhelming. What part feels most difficult right now?";
    }

    if (text.includes("work") || text.includes("job")) {
      return "Work stress can drain your energy. Is it workload, deadlines, or expectations?";
    }

    if (text.includes("family")) {
      return "Family-related stress can feel very personal. What’s been happening?";
    }

    if (text.includes("money") || text.includes("financial")) {
      return "Financial worries can feel heavy. What concerns you the most right now?";
    }

    if (text.includes("future") || text.includes("career")) {
      return "Uncertainty about the future can be scary. What thoughts keep coming back to you?";
    }

    if (
      text.includes("sleep") ||
      text.includes("tired") ||
      text.includes("headache") ||
      text.includes("focus")
    ) {
      return (
        "When stress starts affecting your body, it’s a sign you’ve been carrying too much 😔\n\n" +
        "Would you like a small calming exercise or some music right now?"
      );
    }

    /* ================= DEFAULT ================= */
    return (
      "Thank you for sharing 🤍\n\n" +
      "I’m listening. You can tell me more about what’s been on your mind."
    );
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = { sender: "user", text: input };
    const botMessage = {
      sender: "bot",
      text: therapistReply(input)
    };

    setMessages([...messages, userMessage, botMessage]);
    setInput("");
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter") {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2 className="chat-title">💬 Therapy Chat</h2>
        <p className="chat-subtitle">A safe space to talk</p>
      </div>

      <div className="chat-box">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`message-group ${
              msg.sender === "user" ? "user-group" : "therapist-group"
            }`}
          >
            <div className="message-label">
              {msg.sender === "user" ? "You" : "Therapist"}
            </div>
            <div className={`message ${msg.sender}`}>
              {msg.text}
            </div>
          </div>
        ))}
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Type here when you're ready..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={handleKeyPress}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
